function solve(piles: number[]): number {
    // Sort the array
    piles.sort((a, b) => a - b);
    const n = piles.length;
    let total = 0;

    // Use a min-heap to keep track of the middle elements
    const heap = new MinHeap();

    // Iterate through the array in steps of 3
    for (let i = 0; i < n; i += 3) {
        // Add the current element to the heap
        heap.push(piles[i]);

        // If the heap size exceeds 3, pop the smallest element
        if (heap.size() > 3) {
            heap.pop();
        }

        // The middle element of the triplet is the top of the heap
        total += heap.peek();
    }

    return total;
}

class MinHeap {
    private heap: number[];

    constructor() {
        this.heap = [];
    }

    push(value: number): void {
        this.heap.push(value);
        this.heap.sort((a, b) => a - b);
    }

    pop(): number {
        if (this.heap.length === 0) return 0;
        return this.heap.shift() as number;
    }

    peek(): number {
        return this.heap[0];
    }

    size(): number {
        return this.heap.length;
    }
}
